package com.cognizant.springlearn.service; import java.util.*; import java.util.concurrent.*; import org.springframework.stereotype.*; import com.cognizant.springlearn.model.*;
@Service public class EmployeeService {private final Map<Long,Employee> data=new ConcurrentHashMap<>(); public List<Employee> all(){return data.values().stream().toList();} public Employee add(Employee e){if(data.putIfAbsent(e.id(),e)!=null)throw new IllegalArgumentException("Employee exists");return e;} public Employee update(Employee e){if(!data.containsKey(e.id()))throw new NoSuchElementException("Employee not found");data.put(e.id(),e);return e;} public void delete(long id){if(data.remove(id)==null)throw new NoSuchElementException("Employee not found");}}
